def biggest_source(spec: dict) -> str:
    binary = ["png", "jpg", "gif", "ico", "wasm", "pyc"]
    best_path = ""
    best_size = -1
    for f in spec["files"]:
        base = f["path"].split("/")[-1]
        ext = base.split(".")[-1].lower() if "." in base else ""
        if ext in binary:
            continue
        if f["size"] > best_size or (f["size"] == best_size and f["path"] < best_path):
            best_size = f["size"]
            best_path = f["path"]
    return best_path

