    binary = ["png", "jpg", "gif", "ico", "wasm", "pyc"]
    kept = 0
    for path in spec["paths"]:
        segs = path.split("/")
        base = segs[-1]
        ext = base.split(".")[-1].lower() if "." in base else ""
        if "__pycache__" in segs[:-1]:
            continue
        if base.startswith(".") or ext in binary:
            continue
