def lang_census(spec: dict) -> dict:
    labels = {"py": "Python", "md": "Markdown", "toml": "TOML", "css": "CSS", "js": "JavaScript"}
    tally = {}
    for path in spec["paths"]:
        base = path.split("/")[-1]
        if path.endswith(".jac"):
            lab = "Jac"
        elif "." in base:
            ext = base.split(".")[-1].lower()
            lab = labels.get(ext, ext.upper())
        else:
            lab = "Text"
        tally[lab] = tally.get(lab, 0) + 1
    return {k: tally[k] for k in sorted(tally)}

