def matrix_stack(spec: dict) -> list:
    regs = [0, 0]
    mode = 0
    for op in spec["ops"]:
        if op == "proj":
            mode = 0
        elif op == "mv":
            mode = 1
        else:
            n = int(op.split(":")[1])
            if op.startswith("set:"):
                regs[mode] = n
            elif op.startswith("add:"):
                regs[mode] += n
            else:
                regs[mode] *= n
    return regs

